// Script Continued Below
// dtechTemplateService
// Use this service to hover over items in gojs or other angularjs capabilities
// For example, given the following string, get the first 5 readable characters
// 2.8.3 (Template Updates Addon)  STRY0142161 - Feature allowing for Templates to be copied/cloned
function dtechTemplateService($document, $location, $timeout, $log, $http) {
	var self = this;

	var error = _error;
	var activateTemplateTask = _activateTemplateTask;
	var changeTemplateTaskOrder = _changeTemplateTaskOrder;
	var cloneTemplate = _cloneTemplate;
	var copyTemplateTask = _copyTemplateTask;
	var copyTemplateTaskAndDescendants = _copyTemplateTaskAndDescendants;
	var deactivateTemplateTask = _deactivateTemplateTask;
	var getAssignmentInformation = _getAssignmentInformation;
	var getBaseURL = _getBaseURL;
	var getContextMenuInformation = _getContextMenuInformation;
	var getDurationInformation = _getDurationInformation;
	var getItemMembersInformation = _getItemMembersInformation;
	var getOperationalInformation = _getOperationalInformation;
	var getSubTasksInformationWithList = _getSubTasksInformationWithList;
	var getTaskerFilesInformationWithFiles = _getTaskerFilesInformationWithFiles;
	var getTemplateAPIURL = _getTemplateAPIURL;
	var getUIActionParametersByActionName = _getUIActionParametersByActionName;
	var getUIActionParametersByGUID = _getUIActionParametersByGUID;
	var isTemplateNameUnique = _isTemplateNameUnique;
	var moveTemplateTask = _moveTemplateTask;
	var success = _success;
	return {
		activateTemplateTask: activateTemplateTask,
		changeTemplateTaskOrder: _changeTemplateTaskOrder,
		cloneTemplate: cloneTemplate,
		copyTemplateTask: copyTemplateTask,
		copyTemplateTaskAndDescendants: copyTemplateTaskAndDescendants,
		deactivateTemplateTask: deactivateTemplateTask,
		getAssignmentInformation: getAssignmentInformation,
		getContextMenuInformation: getContextMenuInformation,
		getDurationInformation: getDurationInformation,
		getItemMembersInformation: getItemMembersInformation,
		getOperationalInformation: getOperationalInformation,
		getSubTasksInformationWithList: getSubTasksInformationWithList,
		getTaskerFilesInformationWithFiles: getTaskerFilesInformationWithFiles,
		getUIActionParametersByActionName: getUIActionParametersByActionName,
		getUIActionParametersByGUID: getUIActionParametersByGUID,
		isTemplateNameUnique: isTemplateNameUnique,
		moveTemplateTask: moveTemplateTask
	};

	function _getBaseURL(){
		var protocol = $location.protocol();
		var host = $location.host();
		var baseURL = protocol + "://" + host;
		var port = $location.port() + '';
		if(port && port != ''){
			baseURL += ":" + port;
		}

		return baseURL;		
	}

	function _error(err){
// TODO - handle Error better
		return err.statusText;
	}

	function _activateTemplateTask(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateTaskUpdate/activateTemplateTask';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log.log("dtechTemplateService._activateTemplateTask - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);		
	}
	function _changeTemplateTaskOrder(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateTaskUpdate/changeTemplateTaskOrder';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log.log("dtechTemplateService._changeTemplateTaskOrder - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);		
	}

	function _deactivateTemplateTask(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateTaskUpdate/deactivateTemplateTask';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log.log("dtechTemplateService._deactivateTemplateTask - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);		
	}

	function _getAssignmentInformation(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getAssignmentInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getContextMenuInformation(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId +  '/getContextMenuInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getDurationInformation(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getDurationInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getItemMembersInformation(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getItemMembersInformation';
		var requestBody = "";
		return $http.get(endPoint).then(success, error);
	}

	function _getOperationalInformation(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getOperationalInformation';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getSubTasksInformationWithList(templateTaskId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getSubTasksInformationWithList';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getTaskerFilesInformationWithFiles(templateId){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/getTaskerFilesInformationWithFiles';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getUIActionParametersByActionName(templateTaskId, action_name){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/' + action_name + '/getUIActionParametersByName';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getUIActionParametersByGUID(templateTaskId, action_guid){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + templateTaskId + '/' + action_guid + '/getUIActionParametersByGUID';
		var requestBody = ""; 
		return $http.get(endPoint).then(success, error);
	}

	function _getTemplateAPIURL(){
		var baseURL = getBaseURL();
		var template_api_url = baseURL +
				"/api/x_153465_discovert/template_api/";
		return template_api_url;		
	}

	function _cloneTemplate(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateUpdate/cloneTemplate';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log("dtechTemplateService._cloneTemplate - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);		
	}

	function _copyTemplateTask(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateUpdate/copyTemplateTask';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log("dtechTemplateService._copyTemplateTask - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);
	}

	function _copyTemplateTaskAndDescendants(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateUpdate/copyTemplateTaskAndDescendants';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log("dtechTemplateService._copyTemplateTaskAndDescendants - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);
	}

	function _isTemplateNameUnique(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateUpdate/isTemplateNameUnique';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		return $http.post(endPoint, requestBody).then(success, error);
	}

	function _moveTemplateTask(metaData){
		var template_api_url = getTemplateAPIURL();
		var endPoint = template_api_url + 'templateUpdate/moveTemplateTask';
		var strMetaData = JSON.stringify(metaData);
		var requestBody = strMetaData; 
		$log("dtechTemplateService._moveTemplateTask - endPoint: " + endPoint + " - requestBody: " + requestBody);
		return $http.post(endPoint, requestBody).then(success, error);
	}

	function _success(response){
		return response.data.result;
	}

}
